import{_ as a,o as n,c as e,ag as t}from"./chunks/framework.CanvC6-R.js";const h=JSON.parse('{"title":"Expressions and Statements","description":"","frontmatter":{},"headers":[],"relativePath":"language/core_concepts/expression_and_statements.md","filePath":"language/core_concepts/expression_and_statements.md"}'),i={name:"language/core_concepts/expression_and_statements.md"};function p(o,s,l,c,d,r){return n(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="expressions-and-statements" tabindex="-1">Expressions and Statements <a class="header-anchor" href="#expressions-and-statements" aria-label="Permalink to &quot;Expressions and Statements&quot;">​</a></h1><p>Bliss draws a strict distinction between expressions and statements. This distinction is not a convention — it is enforced by the language.</p><h2 id="expressions" tabindex="-1">Expressions <a class="header-anchor" href="#expressions" aria-label="Permalink to &quot;Expressions&quot;">​</a></h2><p>An expression is any construct that <strong>produces a value</strong>. Expressions can be used anywhere a value is expected — as an initializer, as a function argument, or as a condition.</p><p>The following are expressions in Bliss:</p><p><strong>Literals</strong> — a direct value written in source code.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>21</span></span>
<span class="line"><span>true</span></span>
<span class="line"><span>&quot;Hello&quot;</span></span>
<span class="line"><span>&#39;x&#39;</span></span></code></pre></div><p><strong>Identifiers</strong> — a named value.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x</span></span>
<span class="line"><span>age</span></span>
<span class="line"><span>isReady</span></span></code></pre></div><p><strong>Binary expressions</strong> — two expressions combined with an operator, producing a value.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x + 5</span></span>
<span class="line"><span>age &gt;= 18</span></span>
<span class="line"><span>a &amp;&amp; b</span></span></code></pre></div><p><strong>Unary expressions</strong> — a single expression preceded by an operator.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>!isReady</span></span>
<span class="line"><span>-x</span></span></code></pre></div><p><strong>Function calls</strong> — always an expression in Bliss, regardless of whether the function returns a meaningful value or <code>void</code>.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>add(3, 5)</span></span>
<span class="line"><span>greet(&quot;Alice&quot;)</span></span></code></pre></div><p><strong>Data initialization</strong> — a data type paired with a field initializer block. The block here is part of the expression, not a standalone construct.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User { name = &quot;Alice&quot;, age = 21 }</span></span></code></pre></div><h2 id="statements" tabindex="-1">Statements <a class="header-anchor" href="#statements" aria-label="Permalink to &quot;Statements&quot;">​</a></h2><p>A statement is any construct that <strong>performs an action</strong> but produces no value. Statements cannot be used where a value is expected.</p><p>The following are statements in Bliss:</p><p><strong>Variable declaration</strong> — declares a variable and optionally binds it to an expression.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: i32 = 5;</span></span>
<span class="line"><span>let name: u8[];</span></span></code></pre></div><p><strong>Reassignment</strong> — binds a new expression to an existing variable.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x = x + 1;</span></span>
<span class="line"><span>arr[0] = 10;</span></span></code></pre></div><p><strong>Function definition</strong> — defines a named function.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fx add(x: i32, y: i32) -&gt; i32 {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Control flow</strong> — <code>if</code>, <code>elif</code>, <code>else</code>, and <code>while</code> are all statements.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if ( x &gt; 0 ) {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>while ( isRunning ) {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Blocks</strong> — a <code>{ }</code> block is a statement. It is structural and produces no value on its own. The only context where a block appears as part of an expression is data initialization.</p><p><strong><code>import</code> and <code>use</code></strong> — bring external packages and internal files into scope.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import std;</span></span>
<span class="line"><span>use src.utils;</span></span></code></pre></div><h2 id="the-distinction-in-practice" tabindex="-1">The Distinction in Practice <a class="header-anchor" href="#the-distinction-in-practice" aria-label="Permalink to &quot;The Distinction in Practice&quot;">​</a></h2><p>Because assignment is a statement and not an expression, constructs like the following are <strong>not valid</strong> in Bliss:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: i32 = let y: i32 = 5;  // ❌ declaration is not an expression</span></span>
<span class="line"><span>while ( x = 5 ) { }           // ❌ assignment is not an expression</span></span></code></pre></div><p>A function call, however, is always an expression and can appear as a standalone statement by itself:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>greet(&quot;Alice&quot;);   // valid — expression used as a statement</span></span></code></pre></div>`,36)])])}const u=a(i,[["render",p]]);export{h as __pageData,u as default};
